@Override
public OpenMapRealVector ebeDivide(RealVector v) {
    checkVectorDimensions(v.getDimension());
    OpenMapRealVector res = new OpenMapRealVector(v.getDimension());

    // Process all entries in this vector (non-zero entries)
    Iterator iter = entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        res.setEntry(iter.key(), iter.value() / v.getEntry(iter.key()));
    }

    // Process entries where this vector has zeros but other vector might have non-zeros
    // We need to handle all indices to ensure proper ebe division
    for (int i = 0; i < virtualSize; i++) {
        if (!entries.containsKey(i)) {
            // This vector has 0 at position i, so result will be 0 / v[i]
            double value = 0.0 / v.getEntry(i);
            if (!isDefaultValue(value)) {
                res.setEntry(i, value);
            }
        }
    }

